# ROBUSTNESS PHASE C — Security state machine exhaustive tests
# Manually written, not generated by testgen.py. Do not delete.
#
# ASIL-B safety-critical: SecurityAccess must implement lockout after 3 failed
# key attempts (NRC 0x36 exceededNumberOfAttempts). Tests multi-level isolation,
# key-length validation, double-seed requests, and session interaction.
#
# Run: pytest test_robustness_C_security.py -v --can-interface=simulator
from __future__ import annotations

import pytest
from conftest import (
    _InlineEcuState, _inline_handle, _LEVEL_KEYS, _EcuSimulator,
    SESSION_DEFAULT, SESSION_EXTENDED, SESSION_PROGRAMMING,
    NRC_INCORRECT_MSG_LEN, NRC_CONDITIONS_NOT_CORRECT,
    NRC_REQUEST_OUT_OF_RANGE, NRC_SECURITY_ACCESS_DENIED,
    NRC_INVALID_KEY, NRC_SUB_FUNCTION_NOT_SUPPORTED,
    NRC_SERVICE_NOT_SUPPORTED_IN_SESSION,
    SID_SECURITY_ACCESS, SID_DIAGNOSTIC_SESSION_CONTROL,
    SID_TESTER_PRESENT, SID_WRITE_DATA_BY_ID,
    SID_NEGATIVE_RESPONSE, POSITIVE_RESPONSE_OFFSET,
    ALGO_SEED_LEN, ALGO_KEY_LEN,
)

NRC_EXCEEDED_ATTEMPTS = 0x36  # exceededNumberOfAttempts — not exported but defined by ISO 14229
NRC_REQUEST_SEED_BEFORE_KEY = 0x24  # requestSequenceError

SID_READ_DATA_BY_ID = 0x22
DID_SPARE_PART = 0xF187  # extended session, write_sec=1


def _sim():
    return _InlineEcuState()


def _req(state, pdu):
    return _inline_handle(pdu, state, False)


def _session(state, sub):
    _req(state, bytes([SID_DIAGNOSTIC_SESSION_CONTROL, sub]))


def _nrc(sid, code):
    return bytes([SID_NEGATIVE_RESPONSE, sid, code])


def _request_seed(state, level=1):
    """Request a seed for the given level. Returns the seed bytes or None on failure."""
    sub = (level * 2) - 1  # level 1 → sub 0x01, level 2 → sub 0x03
    resp = _req(state, bytes([SID_SECURITY_ACCESS, sub]))
    if resp is None or resp[0] != SID_SECURITY_ACCESS + POSITIVE_RESPONSE_OFFSET:
        return None
    return bytes(resp[2:])  # seed bytes after [0x67, sub]


def _compute_key(seed, level=1):
    """Compute the correct 4-byte AES-CMAC key for the given seed and level."""
    return _EcuSimulator()._derive_key(seed, level)


def _send_key(state, seed, level=1):
    """Send the correct key. Returns the response."""
    sub = level * 2  # level 1 → sub 0x02, level 2 → sub 0x04
    key = _compute_key(seed, level)
    return _req(state, bytes([SID_SECURITY_ACCESS, sub]) + key)


def _send_wrong_key(state, level=1):
    """Send a definitively wrong 4-byte key."""
    sub = level * 2
    return _req(state, bytes([SID_SECURITY_ACCESS, sub, 0xDE, 0xAD, 0xBE, 0xEF]))


def _unlock(state, level=1):
    """Full correct unlock sequence for the given level. Returns True on success."""
    seed = _request_seed(state, level)
    if seed is None:
        return False
    resp = _send_key(state, seed, level)
    if resp is None or resp[0] != SID_SECURITY_ACCESS + POSITIVE_RESPONSE_OFFSET:
        return False
    return True


class TestSecurityAccessLockout:
    """After 3 wrong key attempts, the ECU must enter lockout (NRC 0x36)."""

    def test_single_wrong_key_returns_nrc_35(self):
        state = _sim()
        _session(state, SESSION_EXTENDED)
        _request_seed(state, 1)
        resp = _send_wrong_key(state, 1)
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_INVALID_KEY, (
            f"First wrong key → NRC 0x35 (invalidKey), got 0x{resp[2]:02X}")

    def test_two_wrong_keys_allows_third_attempt(self):
        state = _sim()
        _session(state, SESSION_EXTENDED)
        # Attempt 1 wrong
        _request_seed(state, 1); _send_wrong_key(state, 1)
        # Attempt 2 wrong
        _request_seed(state, 1); _send_wrong_key(state, 1)
        # Should still be able to request seed for attempt 3
        seed = _request_seed(state, 1)
        assert seed is not None, "Should be able to request seed for attempt 3 after 2 failures"

    def test_three_wrong_keys_triggers_lockout_nrc_36(self):
        """ISO 14229-1 §10.4.5: after maxNumberOfAttempts failures → NRC 0x36."""
        state = _sim()
        _session(state, SESSION_EXTENDED)
        for attempt in range(3):
            seed = _request_seed(state, 1)
            assert seed is not None, f"Seed request should work on attempt {attempt+1}"
            _send_wrong_key(state, 1)
        # Fourth attempt — should be locked out
        seed_resp = _req(state, bytes([SID_SECURITY_ACCESS, 0x01]))
        assert seed_resp is not None and seed_resp[0] == SID_NEGATIVE_RESPONSE, (
            "After 3 wrong keys, requestSeed must fail with NRC")
        assert seed_resp[2] == NRC_EXCEEDED_ATTEMPTS, (
            f"After 3 failed key attempts, NRC 0x36 (exceededNumberOfAttempts) required. "
            f"Got NRC 0x{seed_resp[2]:02X}. Security lockout not implemented in simulator.")

    def test_lockout_persists_after_tester_present(self):
        """TesterPresent must not bypass lockout."""
        state = _sim()
        _session(state, SESSION_EXTENDED)
        for _ in range(3):
            _request_seed(state, 1); _send_wrong_key(state, 1)
        # TesterPresent
        _req(state, bytes([SID_TESTER_PRESENT, 0x00]))
        # Still locked
        resp = _req(state, bytes([SID_SECURITY_ACCESS, 0x01]))
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_EXCEEDED_ATTEMPTS, (
            f"TesterPresent must not reset lockout counter. Got NRC 0x{resp[2]:02X}")

    def test_correct_key_after_single_wrong_resets_counter(self):
        """1 wrong → 1 correct → counter resets → 3 more wrongs lock out."""
        state = _sim()
        _session(state, SESSION_EXTENDED)
        # 1 wrong attempt
        _request_seed(state, 1); _send_wrong_key(state, 1)
        # 1 correct — should reset failure counter
        assert _unlock(state, 1), "Correct key after one wrong must succeed"
        # Now 3 more wrong attempts must still trigger lockout (not after 2)
        state.sec_unlocked.clear()  # clear unlock to re-test
        for _ in range(3):
            seed = _request_seed(state, 1)
            if seed is None:
                pytest.skip("Lockout feature not yet implemented — skipping counter-reset test")
            _send_wrong_key(state, 1)
        resp = _req(state, bytes([SID_SECURITY_ACCESS, 0x01]))
        assert resp is not None and resp[2] == NRC_EXCEEDED_ATTEMPTS


class TestSecurityAccessEdgeCases:
    """Key length validation, double-seed, sequence errors."""

    def test_send_key_without_prior_seed_returns_nrc_24(self):
        """sendKey without requestSeed → NRC 0x24 (requestSequenceError)."""
        state = _sim()
        _session(state, SESSION_EXTENDED)
        resp = _req(state, bytes([SID_SECURITY_ACCESS, 0x02, 0x11, 0x22, 0x33, 0x44]))
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_REQUEST_SEED_BEFORE_KEY, (
            f"sendKey without requestSeed must return NRC 0x24, got 0x{resp[2]:02X}")

    def test_send_key_wrong_length_short_returns_nrc_13(self):
        """sendKey PDU too short (2 bytes instead of 6) → NRC 0x13."""
        state = _sim()
        _session(state, SESSION_EXTENDED)
        _request_seed(state, 1)
        resp = _req(state, bytes([SID_SECURITY_ACCESS, 0x02, 0x11]))  # only 1 key byte
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_INCORRECT_MSG_LEN, (
            f"Short key PDU must return NRC 0x13, got 0x{resp[2]:02X}")

    def test_send_key_wrong_length_long_returns_nrc_13(self):
        """sendKey PDU too long (10 bytes) → NRC 0x13."""
        state = _sim()
        _session(state, SESSION_EXTENDED)
        _request_seed(state, 1)
        resp = _req(state, bytes([SID_SECURITY_ACCESS, 0x02] + [0x11] * 8))  # 8 key bytes
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_INCORRECT_MSG_LEN

    def test_double_seed_request_replaces_pending_seed(self):
        """Requesting seed twice without sending key replaces the pending seed."""
        state = _sim()
        _session(state, SESSION_EXTENDED)
        seed1 = _request_seed(state, 1)
        assert seed1 is not None
        seed2 = _request_seed(state, 1)
        assert seed2 is not None
        # Key derived from seed1 must now be invalid (seed2 replaced it)
        key1 = _compute_key(seed1, 1)
        resp = _req(state, bytes([SID_SECURITY_ACCESS, 0x02]) + key1)
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE, (
            "Key derived from old seed must fail after double requestSeed")

    def test_seed_already_unlocked_returns_zeros(self):
        """requestSeed when already unlocked at that level → seed of 0x00 * N."""
        state = _sim()
        _session(state, SESSION_EXTENDED)
        assert _unlock(state, 1)
        # Request seed again when already unlocked at level 1
        resp = _req(state, bytes([SID_SECURITY_ACCESS, 0x01]))
        assert resp is not None and resp[0] == SID_SECURITY_ACCESS + POSITIVE_RESPONSE_OFFSET
        seed = bytes(resp[2:])
        assert all(b == 0x00 for b in seed), (
            f"requestSeed when already unlocked must return zeros, got {seed.hex()}")

    def test_security_in_default_session_returns_nrc_7f(self):
        state = _sim()
        # Default session
        resp = _req(state, bytes([SID_SECURITY_ACCESS, 0x01]))
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_SERVICE_NOT_SUPPORTED_IN_SESSION

    def test_invalid_subfunction_0x00_returns_nrc_12(self):
        """Sub=0x00 is invalid (must be odd for seed, even for key)."""
        state = _sim()
        _session(state, SESSION_EXTENDED)
        resp = _req(state, bytes([SID_SECURITY_ACCESS, 0x00]))
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        # 0x00 is even → sendKey, but level 0 doesn't exist → should be NRC

    def test_security_too_short_pdu_returns_nrc_13(self):
        state = _sim()
        _session(state, SESSION_EXTENDED)
        resp = _req(state, bytes([SID_SECURITY_ACCESS]))
        assert resp == bytes([SID_NEGATIVE_RESPONSE, SID_SECURITY_ACCESS, NRC_INCORRECT_MSG_LEN])


class TestSecurityLevelIsolation:
    """Security levels must be independent — unlocking L1 does not grant L3 access."""

    def test_correct_unlock_level1_grants_l1_write_access(self):
        state = _sim()
        _session(state, SESSION_EXTENDED)
        assert _unlock(state, 1)
        resp = _req(state, bytes([SID_WRITE_DATA_BY_ID,
                                   (DID_SPARE_PART >> 8) & 0xFF,
                                    DID_SPARE_PART & 0xFF] + [0xAB] * 11))
        assert resp is not None and resp[0] == SID_WRITE_DATA_BY_ID + POSITIVE_RESPONSE_OFFSET

    def test_level1_unlock_does_not_grant_level2_access(self):
        """If a DID needs security level 2, level 1 unlock is insufficient → NRC 0x33."""
        state = _sim()
        _session(state, SESSION_EXTENDED)
        assert _unlock(state, 1)
        assert not state.sec_unlocked.get(2, False), "Level 2 must not be unlocked by level 1"

    def test_security_cleared_on_session_downgrade(self):
        """Downgrading session (extended → default) must clear all security unlocks."""
        state = _sim()
        _session(state, SESSION_EXTENDED)
        assert _unlock(state, 1)
        assert state.sec_unlocked.get(1)
        # Downgrade to default
        _session(state, SESSION_DEFAULT)
        assert not state.sec_unlocked.get(1), (
            "Session downgrade must clear security unlock (ASIL-B safety chain)")
        # Re-upgrade and check DID requires re-auth
        _session(state, SESSION_EXTENDED)
        resp = _req(state, bytes([SID_WRITE_DATA_BY_ID,
                                   (DID_SPARE_PART >> 8) & 0xFF,
                                    DID_SPARE_PART & 0xFF] + [0xAB] * 11))
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_SECURITY_ACCESS_DENIED

    def test_security_cleared_by_ecu_reset(self):
        state = _sim()
        _session(state, SESSION_EXTENDED)
        assert _unlock(state, 1)
        _req(state, bytes([0x11, 0x01]))  # ECUReset hardReset
        assert not state.sec_unlocked.get(1), "ECUReset must clear security unlock"

    def test_security_survives_tester_present(self):
        """TesterPresent must NOT clear security unlock."""
        state = _sim()
        _session(state, SESSION_EXTENDED)
        assert _unlock(state, 1)
        _req(state, bytes([SID_TESTER_PRESENT, 0x00]))
        assert state.sec_unlocked.get(1), "TesterPresent must not clear security unlock"

    def test_full_unlock_flow_level1_write_read_back(self):
        """Full happy path: extended session → unlock L1 → write F187 → read back."""
        state = _sim()
        _session(state, SESSION_EXTENDED)
        assert _unlock(state, 1)
        # Write F187
        write_data = bytes([0x01, 0x02, 0x03, 0x04, 0x05,
                            0x06, 0x07, 0x08, 0x09, 0x0A, 0x0B])
        resp = _req(state, bytes([SID_WRITE_DATA_BY_ID,
                                   (DID_SPARE_PART >> 8) & 0xFF,
                                    DID_SPARE_PART & 0xFF]) + write_data)
        assert resp is not None and resp[0] == SID_WRITE_DATA_BY_ID + POSITIVE_RESPONSE_OFFSET
        # Read back
        resp2 = _req(state, bytes([SID_READ_DATA_BY_ID,
                                    (DID_SPARE_PART >> 8) & 0xFF,
                                     DID_SPARE_PART & 0xFF]))
        assert resp2 is not None and resp2[0] == SID_READ_DATA_BY_ID + POSITIVE_RESPONSE_OFFSET
        assert resp2[3:] == write_data, f"Read-back data mismatch: {resp2[3:].hex()}"

    def test_pending_seed_cleared_on_session_change(self):
        """Requesting seed then changing session must invalidate pending seed."""
        state = _sim()
        _session(state, SESSION_EXTENDED)
        seed = _request_seed(state, 1)
        assert seed is not None
        # Change session — pending seed should be cleared
        _session(state, SESSION_PROGRAMMING)
        _session(state, SESSION_EXTENDED)
        # Sending key derived from old seed must fail
        key = _compute_key(seed, 1)
        resp = _req(state, bytes([SID_SECURITY_ACCESS, 0x02]) + key)
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE, (
            "Key from pre-session-change seed must be rejected after session change")
